import React, { useState, useEffect, useRef } from "react";
import { io } from "socket.io-client";

const socket = io("http://localhost:3001");

export default function ChatPage({ currentUser, friend, onBack }) {
  const [messages, setMessages] = useState([]);
  const [input, setInput] = useState("");
  const chatBoxRef = useRef();

  useEffect(() => {
    socket.emit("register user", currentUser.userId);

    socket.on("chat message", (data) => {
      if (data.senderId === friend.userId || data.senderId === currentUser.userId) {
        setMessages(prev => [...prev, data]);
      }
    });

    return () => socket.off("chat message");
  }, [friend, currentUser]);

  useEffect(() => {
    chatBoxRef.current?.scrollTo(0, chatBoxRef.current.scrollHeight);
  }, [messages]);

  const sendMessage = () => {
    if (!input.trim()) return;
    socket.emit("chat message", {
      senderId: currentUser.userId,
      receiverId: friend.userId,
      message: input
    });
    setInput("");
  };

  return (
    <div style={{ display: "flex", flexDirection: "column", height: "100vh" }}>
      {/* Header */}
      <div style={{ background: "#075E54", color: "white", padding: "15px", display: "flex", alignItems: "center" }}>
        <button onClick={onBack} style={{ marginRight: "10px", background: "transparent", border: "none", color: "white", fontSize: "18px" }}>←</button>
        <h3 style={{ margin: 0 }}>{friend.userId}</h3>
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: "auto", padding: "10px", background: "#e5ddd5" }} ref={chatBoxRef}>
        {messages.map((msg, i) => (
          <div
            key={i}
            style={{
              maxWidth: "70%",
              margin: "5px 0",
              padding: "10px",
              borderRadius: "10px",
              background: msg.senderId === currentUser.userId ? "#dcf8c6" : "#fff",
              alignSelf: msg.senderId === currentUser.userId ? "flex-end" : "flex-start",
              boxShadow: "0 1px 1px rgba(0,0,0,0.2)"
            }}
          >
            {msg.message}
          </div>
        ))}
      </div>

      {/* Input */}
      <div style={{ display: "flex", padding: "10px", background: "#f0f0f0" }}>
        <input
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="Type a message"
          style={{ flex: 1, padding: "10px", borderRadius: "20px", border: "1px solid #ccc" }}
        />
        <button onClick={sendMessage} style={{ marginLeft: "10px", padding: "10px 20px", borderRadius: "20px", background: "#25d366", color: "white", border: "none" }}>
          Send
        </button>
      </div>
    </div>
  );
}
